/**
 * @param {MxObject} operatorDashboardContextSignalR
 * @param {string} serverDetails
 * @param {string} hubName
 * @param {Nanoflow} [transactionBoardcast]
 * @returns {Promise.<boolean>}
 */
export async function ConnectToSignalRHub(operatorDashboardContextSignalR, serverDetails, hubName, transactionBoardcast) {
	// BEGIN USER CODE
	let isConnectionSuccessful = false;
    let reConnectAttempts = 0;

    const operatorDashboardPage = window.mx.ui.getContentForm().path;
	const splitServerDetails = serverDetails.split("|");
    const serverURL = splitServerDetails[0].endsWith('/') ? splitServerDetails[0] : splitServerDetails[0] + '/';
    const token = splitServerDetails[1].includes('Bearer ') ? splitServerDetails[1] : 'Bearer ' + splitServerDetails[1];

	async function loadScript(src) {
        return new Promise((resolve, reject) => {
        const script = document.createElement("script");
        script.src = src;
        script.onload = resolve;
        script.onerror = () => reject(new Error(`Failed to load script: ${src}`));
        document.head.appendChild(script);
        });
    }

	 async function loadScriptLibraries() {
        if (typeof $ === 'undefined') {
            await loadScript("./js/jquery-3.7.1.min.js");
        }

        if (typeof $.connection === 'undefined') {
            await loadScript("./js/jquery.signalR-2.4.3.min.js");
        }

        if (typeof $.connection !== 'undefined' && $.connection.hub.state !== $.signalR.connectionState.connected) {
            await loadScript(serverURL + "CamstarPortal/signalr/hubs");
        }
    }

	async function startSignalRConnection()
	{
		try
		{
			await loadScriptLibraries(); 
            $.connection.hub.url = serverURL + "/CamstarPortal/signalr";
            $.signalR.ajaxDefaults.headers = { Authentication: token };

            let hub = $.connection[hubName];
            let updateQueue = [];
            let isUpdating = false;

            hub.client.receiveResourceSetupTxnUpdate = function (transactionType, latestresourceStatusDataJSON)
            {  
                var resourceStatusDataJSON = JSON.parse(latestresourceStatusDataJSON);
                    
                operatorDashboardContextSignalR.set('LatestResourceStatusDetailJSON', latestresourceStatusDataJSON);
                transactionBoardcast({OperatorDashboardContext: operatorDashboardContextSignalR, transactionType: transactionType});
                   
            }

            async function subscribeToMultipleGroups()
            {
                    if ($.connection.hub.state === $.signalR.connectionState.connected) 
                    {
                        if(operatorDashboardContextSignalR.get('SelectedResource') !== "")
                        {
                            hub.server.subscribeToMultipleGroups(operatorDashboardContextSignalR.get('SelectedResource'));
                            console.log('Subscribed to group Successful, inside connectTosignalR');
                        }
                    }

            }
            
			async function attemptConnection() 
            {
                try {
                        await $.connection.hub.start({ transport: ['webSockets', 'longPolling'] });
                        console.log('Real-time service connection successful.');
                        isConnectionSuccessful = true; 
                        //mfgOperatorContext.set('RealTimeReconnect', false);  
                       // mfgOperatorContext.set('SetTimerOn', false); 
                        subscribeToMultipleGroups(); 	
                } catch (error) {
                        console.error('Failed to connect to the real-time service:', error.message);  
                        isConnectionSuccessful = false;
                        //mfgOperatorContext.set('RealTimeReconnect', true); 
                        //mfgOperatorContext.set('SetTimerOn', true);  
                    }
            }

            await attemptConnection();

            if (!isConnectionSuccessful && reConnectAttempts < maxReConnectAttempts) {
                console.log('Attempting to reconnect to the real-time service.');
                reConnectAttempts++;
                await attemptConnection(); 
            }

            $.connection.hub.reconnected(function()
            {
                    console.log('Real-time service reconnected successfully.');
                    
                    if(window.mx.ui.getContentForm().path === operatorDashboardPage)
                    {
                        subscribeToMultipleGroups(); 
                    }
            });

            $.connection.hub.disconnected(async function () 
            {
                    if(window.mx.ui.getContentForm().path === operatorDashboardPage)
                    {
                        console.log('Disconnected from real-time service. Attempting to reconnect.');
                        if (reConnectAttempts < maxReConnectAttempts)
                        {
                            reConnectAttempts++;
                            await attemptConnection(); 
                        } else {
                            console.log('Maximum reconnect attempts to real-time service reached. ');

                        }
                    }
            });

            window.mx.ui.getContentForm().onNavigation = function () 
            {
                    if ($.connection.hub.state === $.signalR.connectionState.connected)
                        {
                        console.log("Disconnecting from the real-time service.");
                        //$.connection.hub.stop();
                    }
            };  
		}
		catch
		{
			 console.error("Failed to connect to the real-time service");
			 return false; 
		}

		return isConnectionSuccessful;
	}
	return await startSignalRConnection();

	// END USER CODE
}
